// // This comment suggests that the clock gating circuit will activate the clock whenever either enable signal is low, which is the opposite of the intended behavior.
module top_module(
  input  clk_i,
  input  en_i,
  input  test_en_i,
  output clk_o
);reg en_latch;

  always @* begin
    if (!clk_i) begin
      en_latch = en_i | test_en_i;
    end
  end
  assign clk_o = en_latch & clk_i;

endmodule
